INSERT INTO `inventario` (`id`, `nombre_prenda`, `codigo`, `genero`, `marca_prenda`, `categoria`, `descripcion_corta`, `descripcion_larga`, `precio_base`, `estado`, `subcategoria`, `beneficio`, `tipoFaja`, `sistema`, `compresion`, `brasier`, `panties`, `bikini`, `malla`, `balneario`, `pijamacomoda`, `pijamasexy`, `tipolinea`) VALUES
(18, 'BRASIER CORRECTOR DE POSTURA CON COPAS PREHORMADAS SIN ARCO', '11936L', 'mujer', 'leonisa', 'ropainterior', 'Brasier corrector de postura con refuerzo en X. Soporte total, comodidad y múltiples usos.', 'Brasier Corrector de Postura con Refuerzo en X en DuraFit®\r\n• Diseño con refuerzo en X en la espalda que ayuda a llevar los hombros hacia atrás y mejorar la postura\r\n• Doble capa de DuraFit® que brinda soporte firme, suavidad y alta durabilidad\r\n• Copas prehormadas con excelente cubrimiento que ofrecen modelación perfecta del busto\r\n• Ayuda a aliviar molestias en la espalda al promover una posición más erguida\r\n• Cargaderas anchas, suaves y graduables que distribuyen el peso y reducen la presión en los hombros\r\n• Ajuste cómodo que se adapta al cuerpo durante todo el día\r\n• Abrochadura frontal que facilita su uso y brinda mayor practicidad\r\n\r\nUsos recomendados:\r\n• Postquirúrgico: brinda compresión y soporte durante la recuperación\r\n• Uso diario: comodidad extrema para llevarlo todo el día\r\n• Deportivo: soporte ideal para diferentes niveles de actividad\r\n• Lactancia: fácil de usar gracias a su broche frontal\r\n\r\n• Diseño versátil que combina soporte, funcionalidad y confort\r\n• Sensación de firmeza, alivio y bienestar en cada uso', 473.28, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(19, 'Brasier de gran cubrimiento: Deep Coverage Bra', '11995', 'mujer', 'leonisa', 'ropainterior', 'Brasier triangular con arco y encaje. Alto cubrimiento, soporte y modelación natural.', 'Brasier Triangular con Arco, Encaje y Máximo Cubrimiento\r\n• Silueta triangular con copas de alto cubrimiento que envuelven completamente el busto\r\n• Arcos internos que brindan excelente soporte y estabilidad\r\n• Copas en espuma suave y liviana que se adaptan al busto para una modelación natural\r\n• Sin realce incorporado: apariencia más natural y cómoda\r\n• Ideal para busto mediano y grande que busca soporte y cobertura total\r\n• Mayor cubrimiento en sisa y espalda que ayuda a disimular rollitos\r\n• Encaje delicado en copas y base que aporta un look romántico y femenino\r\n• Diseño moderno con detalles sutiles en encaje (puede variar ligeramente)\r\n• Cargaderas anchas, acolchadas, fijas y graduables que brindan máximo confort\r\n• Distribución uniforme del peso para evitar molestias en hombros\r\n• Ajuste cómodo que se adapta perfectamente al cuerpo\r\n• Perfecto para uso diario con soporte confiable\r\n• Sensación de suavidad, seguridad y bienestar durante todo el día', 501.12, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(20, 'BUSTIER DE ESCOTE PROFUNDO CON ARCO Y DOBLE REALCE', '11873', 'mujer', 'leonisa', 'ropainterior', 'Bustier de doble realce con escote superprofundo. Aumenta hasta dos tallas y estiliza tu silueta.', 'Bustier de Doble Realce con Arco y Escote Superprofundo en SmartLace®\r\n• Composición: 81% poliamida – 19% elastano\r\n• Silueta tipo bustier que estiliza la parte alta del abdomen y los laterales\r\n• Copas con espuma suave incorporada que centran, levantan y aumentan hasta dos tallas de busto\r\n• Realce extremo con efecto natural gracias a su diseño interno\r\n• Arcos internos que brindan excelente soporte y definición\r\n• Escote superprofundo que realza y resalta el busto de forma impactante\r\n• Espuma liviana que se adapta al cuerpo y recupera su forma original\r\n• Base con delicados detalles en encaje SmartLace® que aportan sensualidad y elegancia\r\n• Espalda en tul con transparencias y encaje bordado para un look sofisticado\r\n• Cargaderas removibles y multiusos: convencional, cruzado o halter\r\n• Diseño con hilos en contraste que añade un toque femenino y moderno\r\n• Ideal para busto pequeño y regular que busca volumen y protagonismo\r\n• Sensación de realce, seguridad y estilo en cada uso', 452.4, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(21, 'PIJAMA PANTALÓN', '2560062', 'mujer', 'touche', 'pijamas', 'Pijama camisa manga corta en poliéster y straplesS en lycra nylon. Pantalón largo en viscosa.', 'Un estilo donde comodidad y elegancia no riñen, sino que se complementan. Las pijamas se convierten en tus aliadas perfectas para mantener siempre viva la llama de la pasión, el proceso de la conquista se construye día a día. La clave es saber escoger la pijama adecuada para cada ocasión o momento de tu relación.', 501.12, 'si', 'pijamas', '', '', '', '', '', '', '', '', '', '', '', ''),
(22, 'CHALECO COMPRESIVO CORRECTOR DE POSTURA', '11173PLUS ', 'mujer', 'fajate', 'fajas', 'Faja de uso diario de alta compresión y total cubrimiento de espalda. 3 medidas de broches. Con varillas internas para mayor firmeza y corrección de postura. \r\n', 'Esta es una de nuestras fajas de uso diario, reductoras de fuerte compresión y espalda alta. sus broches tienen tres posiciones que se ajustan a tu medida. Es busto libre. Para uso diario que moldea y realza la figura brindando alto control en la zona deseada, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda.\r\nCuenta con 3 varillas internas para brindar mayor firmeza, telas con componentes VivelTex, que nutren, regeneran e hidratan la pie.\r\n', 675.12, 'si', 'none', '', '', '', '', '', '', '', '', '', '', '', ''),
(23, 'BRASIER POSTQUIRÚRGICO Y CORRECTOR DE POSTURA', '11065', 'mujer', 'fajate', 'fajas', 'Brasier postquirúrgico de control medio con soporte, compresión y alto cubrimiento.', '• Elaborado en tela elástica y compresiva que proporciona ajuste firme y confortable\r\n• Alto cubrimiento en busto y espalda para mayor soporte y seguridad durante el uso\r\n• Control medio que ayuda a mejorar la postura y brindar estabilidad en la zona superior del cuerpo\r\n• Espalda de alto cubrimiento diseñada para favorecer una postura más adecuada\r\n• Sistema de ajuste con broche que facilita el uso y permite una mejor adaptación al cuerpo\r\n• Material con spandex que aporta elasticidad, flexibilidad y comodidad\r\n• Diseño pensado para brindar soporte continuo sin limitar el movimiento\r\n• Ideal para procesos postquirúrgicos o para quienes buscan mayor soporte y control en el busto\r\n• Color café, versátil y discreto bajo la ropa\r\n• Acabados suaves que ayudan a reducir molestias y brindan mayor confort durante el uso prolongado', 417.6, 'si', 'brasieres', 'postquirurgica', 'brasier', 'broche', 'medianacompresion', '', '', '', '', '', '', '', ''),
(25, 'BRASIER POSTQUIRÚRGICO ', '11181', 'mujer', 'fajate', 'fajas', 'Brasier postquirúrgico con broches frontales, control de espalda y copas prehormadas.', '• Realza y moldea el busto de manera natural brindando soporte y comodidad durante el uso\r\n• Copas prehormadas sin varillas que ofrecen una forma natural y mayor confort\r\n• Broches frontales o centrales que facilitan el ajuste y la postura de la prenda\r\n• Tiros ajustables que permiten adaptar el brasier de forma personalizada al cuerpo\r\n• Control de espalda que brinda soporte adicional y ayuda a mejorar la postura\r\n• Elaborado en telas PowerNet y Spandex que proporcionan compresión, elasticidad y ajuste seguro\r\n• Tecnología con componentes del Grupo VivelTex: Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol EMI\r\n• Activos que se activan al contacto con la piel ayudando a nutrir, hidratar, regenerar y reafirmar\r\n• Materiales suaves y flexibles ideales para uso prolongado durante el proceso postquirúrgico\r\n• Diseño pensado para brindar bienestar, soporte y recuperación cómoda\r\n• Prenda funcional que combina tecnología textil, confort y modelación natural', 403.68, 'si', 'brasieres', 'postquirurgica', 'brasier', 'broche', 'medianacompresion', '', '', '', '', '', '', '', ''),
(26, 'BRASIER POSTQUIRÚRGICO', '11027', 'mujer', 'fajate', 'fajas', 'Brasier postquirúrgico con copas prehormadas, control medio y soporte cómodo.', '• Nivel de control: Medio\r\n• Zona de moldeo: Busto\r\n• Mecanismo de ajuste: Broche central\r\n• Material principal: Spandex\r\n• Copas prehormadas sin varillas\r\n• Alto cubrimiento y soporte\r\n• Brinda soporte durante la recuperación\r\n• Ayuda a mejorar el proceso de desinflamación\r\n• Mantiene el busto centrado y con forma natural\r\n• Ofrece compresión cómoda y segura\r\n• Ajuste práctico y adaptable al cuerpo', 403.68, 'si', 'brasieres', 'postquirurgica', 'brasier', 'broche', 'medianacompresion', '', '', '', '', '', '', '', ''),
(27, 'BRASIER MATERNO X', '11057', 'mujer', 'fajate', 'ropainterior', 'Brasier materno en algodón con broches para lactancia y soporte cómodo.', '• Nivel de control: Medio\r\n• Uso recomendado: Materna / Lactancia\r\n• Zona de moldeo: Busto\r\n• Mecanismo de ajuste: Broche\r\n• Material principal: Algodón y spandex\r\n• Diseño tipo top con soporte suave\r\n• Facilita el proceso de lactancia gracias a sus broches funcionales\r\n• Brinda soporte cómodo durante el día\r\n• Ayuda a proteger la piel sensible con materiales suaves\r\n• Costuras ultraplanas que reducen molestias y marcas\r\n• Diseño práctico, discreto y versátil para uso diario', 334.08, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(28, 'TOP POSTQUIRÚRGICO FIT 360', '11348', 'mujer', 'fajate', 'fajas', 'Brasier postquirúrgico y deportivo FIT 360 con soporte, compresión y control superior.', '• Nivel de control: Medio\r\n• Zona de moldeo: Busto y espalda\r\n• Mecanismo de ajuste: Broches en hombros y frente\r\n• Copas sin varillas\r\n• Alto cubrimiento y soporte\r\n• Diseño FIT 360 con modelación superior\r\n• Ayuda a mejorar la postura\r\n• Brinda soporte y realce al busto\r\n• Moldea el torso superior y afina la silueta\r\n• Facilita la recuperación postquirúrgica\r\n• Ofrece comodidad para uso diario y deportivo\r\n• Reduce marcas visibles bajo la ropa\r\n• Proporciona soporte adicional durante actividades de alto impacto', 445.44, 'si', 'brasieres', 'postquirurgica', 'brasier', 'broche', 'medianacompresion', '', '', '', '', '', '', '', ''),
(29, 'BRASIER POSTQUIRURGICO PARA BUSTO Y BRAZOS  ', '11377', 'mujer', 'fajate', 'fajas', 'Brasier postquirúrgico multifuncional con soporte alto, refuerzo en X y compresión.', '• Brasier postquirúrgico sin arcos\r\n• Refuerzo en X en espalda\r\n• Tela Powernet de alta compresión\r\n• Abrochadura frontal de 9 ganchos\r\n• Copas de cubrimiento total\r\n• Banda elástica de soporte bajo el busto\r\n• Alto soporte y control\r\n• Ayuda a mejorar la postura\r\n• Brinda soporte al busto, espalda y brazos\r\n• Favorece la recuperación postquirúrgica\r\n• Ayuda a reducir inflamación por retención de líquidos\r\n• Moldea de forma natural y cómoda\r\n• Disimula los laterales y mejora el ajuste corporal\r\n• Facilita el uso diario gracias a su cierre frontal', 570.72, 'si', 'brasieres', 'postquirurgica', 'brasier', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(30, 'BRASIER ESSENTIAL', '15078', 'mujer', 'fajate', 'ropainterior', 'Brasier de alto cubrimiento que estiliza espalda y laterales con soporte total.', '• Zona de moldeo: Busto\r\n• Mecanismo de ajuste: Broche\r\n• Material: Powernet y Spandex\r\n• Alto cubrimiento en espalda, sisa y busto\r\n• Diseño de soporte y definición corporal\r\n• Ayuda a estilizar la espalda y laterales\r\n• Brinda soporte y estabilidad al busto\r\n• Complementa el efecto moldeador de las fajas\r\n• Disimula rollitos en zona axilar y espalda\r\n• Ajuste cómodo y seguro para uso diario', 515.04, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(31, 'BRASIER SALVIA', '15152', 'mujer', 'fajate', 'ropainterior', 'Bra Salvia sin copa con control suave, encaje delicado y soporte en espalda.', '• Color: Blanco\r\n• Nivel de control: Medio\r\n• Uso recomendado: Uso diario\r\n• Zona de moldeo: Busto y espalda\r\n• Mecanismo de ajuste: Broche\r\n• Material: Lycra control\r\n• Diseño sin copa\r\n• Realza el busto de forma natural\r\n• Ayuda a moldear el torso y la espalda\r\n• Brinda mayor cobertura y soporte\r\n• Disimula rollitos en la espalda\r\n• Tela fresca y cómoda para uso prolongado\r\n• Diseño versátil y elegante para el día a día', 668.16, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(32, 'BRASIER RUBI', '15167', 'mujer', 'fajate', 'ropainterior', 'Bra Rubí con copas push up, encaje delicado y control en espalda y laterales.', '• Brasier diseñado para mujeres que buscan realce, soporte y una silueta estilizada con un toque romántico y femenino\r\n• Copas push up que realzan el busto de forma natural, favoreciendo escotes profundos y looks sofisticados\r\n• Delicado encaje que aporta elegancia, sensualidad y un acabado refinado\r\n• Alto cubrimiento en busto y espalda para brindar mayor seguridad y confort durante el uso\r\n• Base ancha que proporciona mejor soporte y ayuda a mantener una apariencia uniforme en la zona axilar y la espalda\r\n• Varillas laterales que ofrecen mayor compresión, estabilidad y ajuste al cuerpo\r\n• Cargaderas fijas en la parte delantera y graduables en la parte posterior para una adaptación personalizada\r\n• Elaborado en lycra control que brinda suavidad, elasticidad y modelación confortable\r\n• Nivel de control medio ideal para moldear suavemente el torso superior\r\n• Ayuda a disimular los rollitos de la zona axilar y la espalda para una silueta más estilizada\r\n• Diseño versátil perfecto para uso diario o para complementar prendas con escotes pronunciados\r\n• Tela suave al tacto y fresca para mayor comodidad durante todo el día', 696, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(33, 'BRASIER TAHITÍ', '15183', 'mujer', 'fajate', 'ropainterior', 'Brasier en lycra y encaje con escote en V, soporte y control en espalda.', '• Elaborado en lycra control y encaje que combinan comodidad, suavidad y sofisticación\r\n• Escote en V que realza el busto de forma favorecedora y elegante\r\n• Copas que brindan soporte, modelación y una apariencia natural del busto\r\n• Base ancha diseñada para ayudar a evitar la formación de bultos o rollitos en la espalda\r\n• Varillas laterales que proporcionan mayor compresión, estabilidad y ajuste en el torso\r\n• Nivel de control medio que contribuye a moldear suavemente la figura\r\n• Ayuda a controlar y definir la zona del busto y la espalda para una apariencia más uniforme\r\n• Diseño versátil ideal para uso diario y diferentes tipos de prendas\r\n• Tela suave y cómoda que permite una sensación agradable durante todo el día\r\n• Acabados delicados que combinan funcionalidad, soporte y elegancia\r\n• Prenda pensada para brindar confianza, comodidad y una silueta armoniosa', 696, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(41, 'FAJA DE ALTA COMPRESION DE MEDIA PIERNA', '11111', 'mujer', 'fajate', 'fajas', 'Faja de alta compresión post quirúrgica, post parto o de uso diario de media pierna, controla las caderas y realza naturalmente los glúteos. Con busto libre, cubrimiento de espalda,corrige la postura y tiene 3 medidas de broches y doble refuerzo abdominal.\r\n\r\n', 'Faja de alta compresión post quirúrgica, post parto o de uso diario, con 3 medidas de broches frontales y busto libre, controla las caderas, corrige la postura dando estabilidad a la espalda mientras moldea y realza naturalmente los glúteos.\r\nLos broches frontales brindan un ajuste más firme en el área abdominal, cuenta con control en la espalda alta y abertura perineal para poder ir al baño sin tener que quitarse toda la faja.\r\nTelas PowerNet y Spandex, con componentes del Grupo VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que se activan al contacto, nutriendo, hidratando, regenerando y reafirmando la piel.', 1057.92, 'si', '', 'postquirurgica', 'body', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(42, 'Panty Faja Postparto con Mayor Cubrimiento de Abdomen', '12885', 'mujer', 'leonisa', 'fajas', 'Panty faja de tiro alto con control total y ajuste graduable. Moldea abdomen y cintura con compresión cómoda, adaptándose a tu cuerpo para una silueta definida.', 'Panty Faja Alto con Control Total y Ajuste en Velcro\r\n• Composición: 86% poliamida – 14% elastano\r\n• Tiro alto con cubrimiento completo de abdomen, cintura y glúteos\r\n• Panel frontal en doble capa PowerSlim® que brinda control fuerte en abdomen\r\n• Laterales con velcro ajustable para regular el nivel de compresión\r\n• Tela DuraFit® suave, elástica y cómoda al contacto con la piel\r\n• Abrochadura inferior con múltiples niveles que facilita el uso y ajuste\r\n• Sensación de soporte firme, seguridad y confort prolongado\r\n• Refuerzo en algodón para mayor higiene y frescura', 528.96, 'si', 'panties', '', '', '', '', '', '', '', '', '', '', '', ''),
(44, 'FAJA ESTILO BODY DE CONTROL FUERTE QUE REALZA LOS GLÚTEOS', '18678N', 'mujer', 'leonisa', 'fajas', 'Body reductor con control fuerte. Moldea abdomen, cintura y realza los glúteos.', 'Faja Body Moldeadora con Control Fuerte en PowerSlim® y Forro DuraFit®\r\n• Composición: 85% poliamida – 15% elastano\r\n• Forro: 74% poliamida – 21% elastano – 5% algodón\r\n• Control fuerte en cintura y abdomen alto, medio y bajo\r\n• Moldea cadera y estiliza la silueta de forma integral\r\n• Elaborado en PowerSlim®: material de alta resistencia que ofrece máxima compresión\r\n• Forro interno en DuraFit®: tela ultradelgada, fresca y suave al contacto con la piel\r\n• Costuras estratégicas que realzan, moldean y afinan los glúteos\r\n• Cierre delantero ultraplano con 3 broches internos para fácil postura y efecto invisible\r\n• Cargaderas termofusionadas, graduables y removibles para mayor versatilidad\r\n• Abertura inferior que brinda mayor practicidad\r\n• Toques de encaje en piernas con ajuste suave y femenino\r\n• Ajuste cómodo que se adapta al cuerpo sin marcar la ropa\r\n• Ideal para uso diario o después del parto\r\n• Diseño funcional que combina control, confort y estilo\r\n• Sensación de firmeza, suavidad y confianza en cada uso', 800.4, 'si', 'CorsetBody', '', '', '', '', '', '', '', '', '', '', '', ''),
(45, 'Mentonera postquirúrgica facial con soporte ajustable y compresión', '11513', 'mujer', 'fajate', 'accesorios', '- Acelera el proceso de cicatrización\r\n- Ayuda a reafirmar y tonificar los tejidos del rostro\r\n- Sirve como un reductivo de papada y cuello\r\n- Su diseño lo vuelve muy fácil de usar\r\n- Minimiza la inflamación\r\n- Detiene la pérdida de sangre', 'Mentonera postquirúrgica ideal para procedimientos faciales como estiramiento de rostro, levantamiento de cejas, liposucción en cara y cuello, cirugía maxilofacial, y más. Su diseño con ajuste de velcro en la parte superior permite un control personalizado según tus necesidades.\r\n\r\nElaborada en powernet 100% con forro de algodón, esta mentonera ofrece soporte mejorado para mayor comodidad. Es ligera, transpirable y duradera, manteniéndote fresco y cómodo durante todo el día.', 473.28, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(46, 'FAJA DE CONTROL TOTAL', '11010', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica o de uso diario de alto control con cierre lateral, cuenta con brasier incluido, cubrimiento de espalda y doble refuerzo abdominal.', '\"Faja postquirúrgica de alto control con cubrimiento en espalda que beneficia la región lumbar, alivia, evita las luxaciones y dolores de espalda, cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme. Ayuda a que las áreas tratadas duelan mucho menos, gracias a la compresión perfecta que brinda al cuerpo. Acelera el proceso de desinflamación, ayudando a una recuperación mas rápida. Acelera el proceso de cicatrización gracias a los componentes impregnados en las telas patentadas (Gingko Biloba, Vitamina E, Algas Marinas, Cosmacol Emi). Ayuda a que la piel se adhiera mas firme al músculo , evitando la retención de líquidos y la formación de fibrosis. Contribuye al drenaje linfático de los tejidos inflamados.Cuenta también con una abertura perineal, para poder ir al baño sin necesidad de quitarse toda la faja.', 1322.4, 'si', '', 'postquirurgica', 'controltotal', 'cierre', 'altacompresion', '', '', '', '', '', '', '', ''),
(47, 'Panty short moldeador de control medio con realce de glúteos y efecto adelgazante', '11510', 'mujer', 'fajate', 'fajas', 'Short de control medio que estiliza la figura y disimula la celulitis. Ideal para pantalones ajustados, vestidos o faldas, brinda comodidad y control con su tejido bidireccional. El tiro alto y la pretina de doble capa controlan el abdomen bajo y la cintura.', '- Tejido bidireccional que controla y brinda comodidad.\r\n- Doble capa de tela fusionada que controla el abdomen medio y bajo.\r\n- Delicado encaje que se adhiere y permite una perfecta sujeción.\r\n- Disimula la celulitis y evita el roce de los muslos.\r\n- Elástico recogido en el centro que genera un efecto de glúteos más redondeados.\r\n- Pretina doble fusionada que moldea y estiliza el derrier.\r\n- Moldea los glúteos, los centra, realza y define.', 675.12, 'si', 'short', 'levantagluteos', 'shorts', 'lizo', 'medianacompresion', '', '', '', '', '', '', '', ''),
(49, 'CAMISETA DE CONTROL - UNA FIGURA MOLDEADA AL INSTANTE', '15824', 'mujer', 'leonisa', 'fajas', 'Camiseta de control fuerte que moldea tu torso y mejora tu postura con total comodidad.', 'Camiseta de Control Fuerte en DuraFit® + PowerSlim® con Doble Escote\r\n• Control fuerte en abdomen alto, medio, bajo, cintura y espalda\r\n• Poder doble capa: DuraFit® + PowerSlim® para máxima compresión y modelación\r\n• Ayuda a corregir la postura y mantener la espalda erguida\r\n• Moldea el busto y realza el escote de forma natural\r\n• Alto cubrimiento en sisa que disimula los rollitos bajo el brazo\r\n• Diseño versátil con doble escote: úsala en cuello redondo o en V\r\n• No se enrolla ni se sube en la cintura para mayor comodidad\r\n• Ajuste firme, seguro y adaptable al cuerpo\r\n• Ideal para usar como prenda interior o exterior\r\n• Sensación de control, soporte y confianza durante todo el día', 341.04, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(50, 'BODY REDUCTOR CON EFECTO LEVANTACOLAS', '18676', 'mujer', 'leonisa', 'fajas', 'Body reductor hasta la rodilla con efecto levantacola. Moldea y estiliza tu figura.', 'Faja Body Reductora hasta la Rodilla con Efecto Levantacola en PowerSlim®\r\n• Diseño tipo body con cubrimiento hasta la rodilla para control total\r\n• Reducción en abdomen alto, medio y bajo, cintura, espalda y piernas\r\n• Elaborada en PowerSlim®: material de alta compresión y durabilidad\r\n• Doble capa con DuraFit® que aporta suavidad y frescura al contacto con la piel\r\n• Derriere descubierto que genera un efecto levantacola natural\r\n• Costuras estratégicas que moldean y estilizan la silueta\r\n• Busto libre para usar con tu brasier favorito\r\n• Cargaderas graduables y removibles para mayor versatilidad\r\n• Cierre delantero con 3 broches internos que facilita su postura\r\n• Abertura inferior que brinda practicidad durante el uso\r\n• Ajuste firme que se adapta al cuerpo sin incomodar\r\n• Ideal para uso diario o para lograr una figura más definida bajo cualquier prenda\r\n• Diseño funcional que combina control, soporte y feminidad\r\n• Sensación de firmeza, suavidad y confianza en cada uso', 626.4, 'si', 'CorsetBody', '', '', '', '', '', '', '', '', '', '', '', ''),
(51, 'FAJA MASCULINA POSTQUIRÚRGICA', '11016', 'hombre', 'fajate', 'fajas', 'Faja postquirúrgica o de uso diario , estilo sisa y espalda alta que mejora la postura. Su cierre central permite mayor ajuste. Ejerce control y reducción en abdomen y piernas.', 'Faja de control total, postquirúrgica o de uso diario, estilo sisa y espalda alta que mejora la postura. Su cierre central permite mayor ajuste. Ejerce control y reducción en abdomen y piernas.\r\nLuego de una intervención quirúrgica, ayuda a que las áreas tratadas duelan mucho menos, gracias a la compresión perfecta que brinda al cuerpo. Acelera el proceso de desinflamación, ayudando a una recuperación mas rápida. Acelera el proceso de cicatrización gracias a los componentes impregnados en las telas patentadas (Gingko Biloba, Vitamina E, Algas Marinas, Cosmacol Emi). Ayuda a que la piel se adhiera mas firme al músculo , evitando la retención de líquidos y la formación de fibrosis. Contribuye al drenaje linfático de los tejidos inflamados.', 1148.4, 'si', '', 'postquirurgica', 'controltotal', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(52, 'BRASILERA CON TUL TRANSPARENTE', '131073', 'mujer', 'ellipse', 'ropainterior', 'Brasilera en tul elastico transparente con aplique cortado a laser, con sesgos en terciopelo.', 'Brasilera en tul elastico transparente con aplique cortado a laser, con sesgos en terciopelo.\r\n\r\n', 180.96, 'si', 'panties', '', '', '', '', '', '', '', '', '', '', '', ''),
(53, 'CINTURÓN DEPORTIVO LÁTEX', '11206', 'mujer', 'fajate', 'accesorios', 'Cinturón deportivo, cintura de avispa de alto rendimiento.\r\n\r\n', 'Cinturón látex alto rendimiento, cuenta con una tela exterior que recubre el látex para conservar una mejor apariencia, cuenta con elásticos y velcro para garantizar un ajuste perfecto en la cintura, cuida tu zona lumbar a la hora de levantar peso.\r\nLa función del látex es elevar la temperatura corporal, eliminar líquidos, toxinas y favorecer la eliminación de tejidos adiposos, además de combatir la celulitis.\r\nTelas elaboradas con látex 100% natural e hipoalergénico, se recomienda usar máximo entre 6 a 8 horas diarias.\r\n', 417.6, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(54, 'BRASIER AIYANA', '15193', 'mujer', 'fajate', 'ropainterior', 'Delié tiene las prendas perfectas para elevar tu feminidad a otro nivel, nuestro brasier Aiyana te dará la sensualidad y seguridad que tanto buscas con su hermoso encaje en el centro de las copas, la base delantera y la parte posterior para brindarte un estilo más elegante, además con su excelente cubrimiento de busto y espalda por su base ancha evitarás que se formen rollitos y te veas mucho mejor, su diseño con cargaderas graduables y varillas laterales te ayudarán a tener una mayor compresión y ajuste de la prenda.', 'Nivel de control\r\nMedio\r\nUsos recomendados\r\nUso-diario\r\nZona de moldeo\r\nBusto\r\nMecanismos de ajuste\r\nBroche\r\nMaterial\r\nLycra control\r\nBeneficios\r\nRealza tu busto. Control y moldeo en abdomen y espalda.\r\nCuidados de la prenda\r\nLava a mano y por separado con jabón suave, preferiblemente de Fájate. No utilices blanqueador, no lo exprimas, ni aplanches. No lo retuerzas ya que se puede dañar la copa. Seca a la sombra. Al momento de ponértelo evita usar accesorios como anillos, pulseras o uñas largas.', 696, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(56, 'FAJA PANTY ', '11197', 'mujer', 'fajate', 'fajas', 'Faja tipo panty de mediana compresión, para control de abdomen que trabaja como faja moldeadora y realza los glúteos de forma natural.\r\n', 'Faja Panty de mediana compresión, que ayuda a difinir las curvas, controla el abdomen, caderas y también moldea los glúteos.\r\nNo tiene broches ni cierres, lo que la vuelve prácticamente invisible bajo la ropa exterior.\r\nSe considera una prenda interior.\r\nDisponible en color cocoa, beige, blanco y negro.\r\nTelas PowerNet y Spandex, con componentes del Grupo VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que se activan al contacto, nutriendo, hidratando, regenerando y reafirmando la piel. ', 556.8, 'si', '', 'levantagluteos', 'shorts', 'lizo', 'altacompresion', '', '', '', '', '', '', '', ''),
(57, 'FAJA BODY MOLDEADORA TIPO CACHETERO', '11046', 'mujer', 'fajate', 'fajas', 'Faja de uso diario busto libre, estilo cachetero, con cierre lateral, moldea y realza la figura brindando alto control en la zona deseada. ', 'Es una faja que deja el busto libre, tiene una cremallera lateral con broches internos que permite un mayor ajuste. Faja postquirúrgica o de uso diario que moldea y realza la figura brindando alto control en la zona deseada, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda,moldea y levanta los glúteos,con control de espalda. Cuenta con una abertura prineal para poder ir baño sin necesidad de quitarse toda la faja. ', 946.56, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(59, 'FAJA DE ALTA COMPRESION LIPO REDUCTORA', '11047', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica o post parto, con refuerzo abdominal, 3 medidas de broches, moldea glúteos, controla piernas y caderas, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda.', '\"Faja postquirúrgica o de uso diario que moldea y realza la figura brindando alto control en la zona deseada, disimula la flacidez y da firmeza a la piel,permite que la piel se contraiga y se adhiera firmemente al musculo, disminuye la incomodidad y la sensación de vacío del abdomen, ayuda a que los órganos internos regresen a su posición, corrige la postura aliviando los dolores de espalda. Controla y moldea glúteos y piernas. Tiene 3 medidas de broches regulables y abertura perineal para poder ir al baño sin necesidad de quitarse toda la faja. \r\nTejidos con Viveltex (Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi); una combinación de componentes que hidratan, nutren, regeneran, cicatrizan y tonifican la piel, éstos se liberan con el contacto con la piel.\"', 1113.6, 'si', '', 'postquirurgica', 'bustolibre', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(60, 'FAJA DE ALTA COMPRESION LIPO REDUCTORA', '11047PLUS', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica o post parto, con refuerzo abdominal, 3 medidas de broches, moldea glúteos, controla piernas y caderas, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda.', '\"Faja postquirúrgica o de uso diario que moldea y realza la figura brindando alto control en la zona deseada, disimula la flacidez y da firmeza a la piel,permite que la piel se contraiga y se adhiera firmemente al musculo, disminuye la incomodidad y la sensación de vacío del abdomen, ayuda a que los órganos internos regresen a su posición, corrige la postura aliviando los dolores de espalda. Controla y moldea glúteos y piernas. Tiene 3 medidas de broches regulables y abertura perineal para poder ir al baño sin necesidad de quitarse toda la faja. \r\nTejidos con Viveltex (Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi); una combinación de componentes que hidratan, nutren, regeneran, cicatrizan y tonifican la piel, éstos se liberan con el contacto con la piel.\"', 1155.36, 'si', 'none', 'postquirurgica', 'bustolibre', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(61, 'FAJA BUSTO LIBRE DE MEDIA PIERNA', '11048', 'mujer', 'fajate', 'fajas', 'Faja de alta compresión post quirúrgica o de uso diario, con cierre lateral, busto libre, controla las caderas, corrige la postura dando estabilidad a la espalda mientras moldea y realza naturalmente los glúteos. ', 'Faja de alta compresión post quirúrgica o de uso diario, con cierre lateral y busto libre, controla las caderas, corrige la postura dando estabilidad a la espalda mientras moldea y realza naturalmente los glúteos. \r\nSu cierre lateral hace que sea prácticamente invisible bajo la ropa, cuenta con control en la espalda alta y abertura perineal para poder ir al baño sin tener que quitarse toda la faja.\r\nTelas PowerNet y Spandex, con componentes del Grupo VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que se activan al contacto, nutriendo, hidratando, regenerando y reafirmando la piel.  ', 1113.6, 'si', '', 'postquirurgica', 'bustolibre', 'cierre', 'altacompresion', '', '', '', '', '', '', '', ''),
(62, 'FAJA BUSTO LIBRE DE MEDIA PIERNA', '11048PLUS', 'mujer', 'fajate', 'fajas', 'Faja de alta compresión post quirúrgica o de uso diario, con cierre lateral, busto libre, controla las caderas, corrige la postura dando estabilidad a la espalda mientras moldea y realza naturalmente los glúteos. ', 'Faja de alta compresión post quirúrgica o de uso diario, con cierre lateral y busto libre, controla las caderas, corrige la postura dando estabilidad a la espalda mientras moldea y realza naturalmente los glúteos. \r\nSu cierre lateral hace que sea prácticamente invisible bajo la ropa, cuenta con control en la espalda alta y abertura perineal para poder ir al baño sin tener que quitarse toda la faja.\r\nTelas PowerNet y Spandex, con componentes del Grupo VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que se activan al contacto, nutriendo, hidratando, regenerando y reafirmando la piel.', 1141.44, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(63, 'FAJA POSTQUIRÚRGICA DE ALTA COMPRESIÓN ', '11052', 'mujer', 'fajate', 'fajas', 'Faja post quirúrgica, post parto o de uso diario con brasier incorporado. Su diseño ofrece una perfecta compresión  en el abdomen, control de espalda y moldeo de senos, glúteos y piernas, cuenta con 3 niveles de broches y abertura perineal.', 'Cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos.Acelera la recuperación y los buenos resultados de procedimientos quirúrgicos y estéticos.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel, contribuyendo así a conseguir los resultados deseados luego de cualquier intervencion quirúrgica o estética. ', 1273.68, 'si', 'none', 'postquirurgica', 'controltotal', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(64, 'FAJA POSTQUIRÚRGICA DE ALTA COMPRESIÓN ', '11052PLUS', 'mujer', 'fajate', 'fajas', 'Faja post quirúrgica, post parto o de uso diario con brasier incorporado. Su diseño ofrece una perfecta compresión  en el abdomen, control de espalda y moldeo de senos, glúteos y piernas, cuenta con 3 niveles de broches y abertura perineal.', 'Cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos.Acelera la recuperación y los buenos resultados de procedimientos quirúrgicos y estéticos.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel, contribuyendo así a conseguir los resultados deseados luego de cualquier intervencion quirúrgica o estética. ', 1322.4, 'si', 'none', 'postquirurgica', 'controltotal', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(65, 'FAJA MOLDEADORA TIPO CACHETERO', '11053', 'mujer', 'fajate', 'fajas', 'Faja de uso diario, con brasier incluido, cierre lateral, estilo cachetero, con encaje siliconado anti deslizante.', 'Faja postquirúrgica o de uso diario de alto control con cubrimiento en espalda que beneficia la región lumbar, alivia, evita las luxaciones y dolores de espalda, cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos.\r\nAcelera la recuperación y los buenos resultados de procedimientos quirúrgicos y estéticos además de ser un aliado en el uso diario.\r\nTelas con componentes VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que ayudan a nutrir, regenerar, hidratar, cicatrizar y tonificar la piel. ', 1071.84, 'si', 'none', 'postquirurgica', 'body', 'cierre', 'altacompresion', '', '', '', '', '', '', '', ''),
(66, 'FAJA BODY REDUCTORA TIPO CACHETERO', '11066', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica, post parto o de uso diario que moldea y realza la figura brindando alto control en la zona deseada, de busto libre con control de espalda y moldeo natural de glúteos.\r\nCuenta con 3 medidas de broches para ir regulando según se vaya reduciendo medidas. \r\n\r\n', 'Faja postquirúrgica, post parto o de uso diario que moldea y realza la figura brindando alto control en la zona deseada.\r\nDe busto libre y 3 medidas de broches para ir ajustando según se reduce medidas, tiene doble refuerzo abdominal que ayuda aplanar el vientre y recuperar la figura luego del parto, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda. Estilo cachetero, con encaje siliconado que no se marca bajo la ropa, es anti deslizante y tiene abertura perineal.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel, contribuyendo así a conseguir los resultados deseados luego de cualquier intervención quirúrgica o estética.', 946.56, 'si', 'none', 'postquirurgica', 'body', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(67, 'FAJA BODY REDUCTORA TIPO CACHETERO', '11066PLUS', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica, post parto o de uso diario que moldea y realza la figura brindando alto control en la zona deseada, de busto libre con control de espalda y moldeo natural de glúteos.\r\nCuenta con 3 medidas de broches para ir regulando según se vaya reduciendo medidas. \r\n', 'Faja postquirúrgica, post parto o de uso diario que moldea y realza la figura brindando alto control en la zona deseada.\r\nDe busto libre y 3 medidas de broches para ir ajustando según se reduce medidas, tiene doble refuerzo abdominal que ayuda aplanar el vientre y recuperar la figura luego del parto, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda. Estilo cachetero, con encaje siliconado que no se marca bajo la ropa, es anti deslizante y tiene abertura perineal.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel, contribuyendo así a conseguir los resultados deseados luego de cualquier intervención quirúrgica o estética.\r\n', 1002.24, 'si', 'none', 'postquirurgica', 'body', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(68, 'FAJA MOLDEADORA STRAPPLES TIPO CACHETERO', '11068', 'mujer', 'fajate', 'fajas', 'Faja de uso diario que moldea y realza la figura brindando alto control en la zona deseada, de busto libre, con cierre lateral y abertura perineal, moldea y levanta los glúteos, disimula la flacidez y da firmeza a la piel, \r\n', 'Faja de uso diario que moldea y realza la figura brindando alto control en la zona deseada, con cierre lateral que la hace menos visible bajo la ropa exterior, tiene broches internos para brindar mayor firmeza, cuenta con una abertura perineal para poder ir al baño sin necesidad de quitarse toda la faja.\r\nEs strapless, puede usarse sin tiros y cuenta con una silicona que hace que se adhiera a la piel y no se baje, levanta los glúteos, disimula la flacidez y da firmeza a la piel.\r\nEs estilo cachetero, tiene un encaje siliconado que no se marca bajo la ropa y es antideslizante para que no se arrolle. \r\nEl uso diario ayuda a moldear la figura y reducir medidas.\r\n\r\n', 946.56, 'si', 'none', 'postquirurgica', 'body', 'cierre', 'altacompresion', '', '', '', '', '', '', '', ''),
(69, 'FAJA INVISIBLE DE CONTROL MEDIO', '11084', 'mujer', 'fajate', 'fajas', 'Faja de mediana compresión de uso portquirúrgico o diario, controla y moldea glúteos y piernas.\r\n', 'Faja de mediana compresión, en el uso postquirúrgico, se utiliza en los primeros 10 días del post operatorio, ya que ejerce un moldeo suave, es también ideal para dormir en este proceso, ya que no tiene cierres ni broches que puedan causar alguna molestia y al ser de mediana compresión permite la correcta circulación y oxigenación de la sangre, permitiendo así un mejor descanso.\r\nPara el uso diario, es ideal para usar bajo vestidos o prendas ajustadas, ya que al no tener broches ni cierres, la hace invisible bajo la ropa. Está elaborada con una tela suave que simula la textura de la piel.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel.\r\n', 696, 'si', 'none', 'postquirurgica', 'bustolibre', 'lizo', 'medianacompresion', '', '', '', '', '', '', '', ''),
(70, 'FAJA POSTQUIRÚRGICA TIPO CACHETERO', '11086', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica, post parto o de uso diario, tipo cachetero con brasier incluido. Ajustable en 3 niveles de broches.\r\n\r\n', 'Faja liporeductora, estilo cachetero con brasier y abertura perineal. Su diseño con broches te permite ajustarla a tres niveles. De alto control con cubrimiento en espalda que beneficia la región lumbar, alivia y evita las luxaciones y dolores de espalda, cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel.\r\n\r\n', 1009.2, 'si', 'none', 'postquirurgica', 'body', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(71, 'FAJA POSTQUIRÚRGICA TIPO CACHETERO', '11086PLUS', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica, post parto o de uso diario, tipo cachetero con brasier incluido. Ajustable en 3 niveles de broches.\r\n', 'Faja liporeductora, estilo cachetero con brasier y abertura perineal. Su diseño con broches te permite ajustarla a tres niveles. De alto control con cubrimiento en espalda que beneficia la región lumbar, alivia y evita las luxaciones y dolores de espalda, cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel.\r\n', 1050.96, 'si', 'none', 'postquirurgica', 'body', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(72, 'FAJA ESTILO CACHETERO STRAPLESS', '11106', 'mujer', 'fajate', 'fajas', 'Faja tipo strapless, reductor con encaje siliconado. Con 3 medidas de broches. Moldea y realza la figura brindando alto control en la zona deseada, disimula la flacidez y da firmeza a la piel. \r\n', 'Faja de uso diario que moldea y realza la figura brindando alto control en la zona deseada, tiene tres medidas de broches, cuenta con una abertura perineal para poder ir al baño sin necesidad de quitarse toda la faja.\r\nEs senos libres, strapless, puede usarse sin tiros y cuenta con una silicona que hace que se adhiera a la piel y no se baje, levanta los glúteos, disimula la flacidez y da firmeza a la piel.\r\nEs estilo cachetero, tiene un encaje siliconado en la pierna que no se marca bajo la ropa y es antideslizante para que no se arrolle. \r\nEl uso diario ayuda a moldear la figura y reducir medidas.\r\n\r\n', 932.64, 'si', 'none', 'postquirurgica', 'body', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(73, 'FAJA DE ALTA COMPRESION DE MEDIA PIERNA', '11111PLUS', 'mujer', 'fajate', 'fajas', 'Faja de alta compresión post quirúrgica, post parto o de uso diario de media pierna, controla las caderas  y realza naturalmente los glúteos. Con busto libre, cubrimiento de espalda,corrige la postura y tiene 3 medidas de broches y doble refuerzo abdominal.\r\n', 'Faja de alta compresión post quirúrgica, post parto o de uso diario, con 3 medidas de broches frontales y busto libre, controla las caderas, corrige la postura dando estabilidad a la espalda mientras moldea y realza naturalmente los glúteos. \r\nLos broches frontales brindan un ajuste más firme en el área abdominal, cuenta con control en la espalda alta y abertura perineal para poder ir al baño sin tener que quitarse toda la faja.\r\nTelas PowerNet y Spandex, con componentes del Grupo VivelTex (Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi) que se activan al contacto, nutriendo, hidratando, regenerando y reafirmando la piel.\r\n', 1099.68, 'si', 'none', '', '', '', '', '', '', '', '', '', '', '', ''),
(74, 'CINTURILLA STRAPLESS', '11006', 'mujer', 'fajate', 'fajas', 'Faja cinturilla de uso diario con diseño strapless, tiene tres niveles de broches regulables que definen tu cintura. Contiene varillas internas a los costados para mayor firmeza y mejor definición de la cintura.', 'CARACTERÍSTICAS\r\nColor: Cocoa\r\nGénero: Mujer\r\nNivel de control: Alta\r\nZona de control: Abdominal\r\nMecanismos de ajuste: Broche\r\nMaterial: powernet, spandex\r\n\r\nCuidados de la prenda\r\n? El lavado: preferiblemente A MANO. Evite el uso de secadora. \r\n? Utilizar preferiblemente el Jabón Fajate\r\n? Evite usar ACCESORIOS que puedan dañar la prenda en el momento de ponerla (anillos, pulseras y uñas largas) \r\n? Lavar separadamente \r\n? Secar a la sombra\r\n? No utilizar blanqueadores\r\n', 570.72, 'si', 'none', '', '', '', '', '', '', '', '', '', '', '', ''),
(75, 'FAJA A LA RODILLA CON CUBRIMIENTO  DE BUSTO Y BRAZOS', '11008', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica con brasier y cobertura completa de espalda y brazos, ideal para postoperatorios de brazos, espalda y busto.\r\n', 'BENEFICIOS:\r\n- Detalle de encaje delicado en el ruedo de la pierna.\r\n- Broches que separan el torso para lactancia o asepsia en cirugías. \r\n- Forrada en lycra con microcápsulas que liberan vitaminas y componentes para realzar y definir glúteos.\r\n- Costuras planas para mayor comodidad y control.\r\n- Uso postquirúrgico, postparto o diario.\r\n', 1294.56, 'si', 'none', 'postquirurgica', 'controltotal', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(76, 'FAJA CHALECO MASCULINO ', '11017', 'hombre', 'fajate', 'fajas', 'Es una faja tipo camisilla que ayuda a mantener una correcta postura y te brinda un firme soporte abdominal. Tiene 3 medidas broches.', 'Es una faja tipo camisilla que ayuda a mantener una correcta postura y te brinda un firme soporte abdominal. Tiene 3 medidas broches para poder ir ajustando según baja la inflamación luego de una intervención quirúrgica.Ideal también para uso diario. \r\nTelas con componentes que se activan al contacto con la piel (Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi), ayudando a regenerar, cicatrizar, humectar y nutrir la piel.\r\n', 932.64, 'si', 'none', 'corredorpostura', 'masculino', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(77, 'FAJA CHALECO MASCULINO (PLUS)', '11017PLUS', 'hombre', 'fajate', 'fajas', 'Es una faja tipo camisilla que ayuda a mantener una correcta postura y te brinda un firme soporte abdominal. Tiene 3 medidas broches.\r\n', 'Es una faja tipo camisilla que ayuda a mantener una correcta postura y te brinda un firme soporte abdominal. Tiene 3 medidas broches para poder ir ajustando según baja la inflamación luego de una intervención quirúrgica.Ideal también para uso diario. \r\nTelas con componentes que se activan al contacto con la piel (Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi), ayudando a regenerar, cicatrizar, humectar y nutrir la piel.', 974.4, 'si', 'none', 'corredorpostura', 'masculino', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(78, 'MENTONERA POSTQUIRÚRGICA CON CUBRIMIENTO DE CUELLO ', '11029', 'mujer', 'fajate', 'accesorios', 'Accesorio Postquirúrgico para la recuperación de traumas por cirugías de mentón o de cara.\r\n', 'MENTONERA POSTQUIRURGICA CON CUBRIMIENTODE CUELLO Y ROSTRO PARA LA RECUPERACION DE TRAUMA POR CIRUGIA  DE MENTON O DE CARA. \r\n', 431.52, 'si', 'none', 'postquirurgica', '', '', '', '', '', '', '', '', '', '', ''),
(79, 'PRENDA COMPRESIVA CARA', '11031', 'mujer', 'fajate', 'accesorios', 'Faja postquirúrgica para mentón y orejas.', 'Faja postquirúrgica para mentón y orejas. Ayuda a la recuperación tras una intervención quirúrgica.Brinda el ajuste adecuado para aliviar dolores y contribuir con los buenos resultados de la cirugía. ', 250.56, 'si', 'none', '', '', '', '', '', '', '', '', '', '', '', ''),
(80, 'MANGAS INDIVIDUALES DE USO QUIRÚRGICO', '11034', 'mujer', 'fajate', 'accesorios', 'Accesorio postquirúrgico para brazos con sistema de broches que se adhieren al brasier.\r\n', 'Accesorio postquirúrgico para brazos con sistema de broches que se adhieren al brasier.\r\n', 153.12, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(81, 'BANDA DE BUSTO FAJATE ', '11037', 'mujer', 'fajate', 'accesorios', 'Accesorio para el Busto, ideal en los procesos y cuidados postquirúrgicos\r\n', 'Accesorio para el Busto, ideal en los procesos y cuidados postquirúrgicos \r\n', 313.2, 'si', 'none', '', '', '', '', '', '', '', '', '', '', '', '');
INSERT INTO `inventario` (`id`, `nombre_prenda`, `codigo`, `genero`, `marca_prenda`, `categoria`, `descripcion_corta`, `descripcion_larga`, `precio_base`, `estado`, `subcategoria`, `beneficio`, `tipoFaja`, `sistema`, `compresion`, `brasier`, `panties`, `bikini`, `malla`, `balneario`, `pijamacomoda`, `pijamasexy`, `tipolinea`) VALUES
(82, 'FAJA MATERNA ', '11044', 'mujer', 'fajate', 'fajas', 'Faja materna tipo cachetero, brinda soporte en espalda y abdomen bajo que ayuda a sostener el peso del vientre y previene los dolores lumbares.', 'Faja materna, diseñada para brindar comodidad y seguridad en el proceso de gestación, se recomienda usar a partir de la semana 25 del embarazo, debido a que previene el dolor e inflamación de los pies al proporcionar un soporte en el abdomen bajo que ayuda a sostener el peso del vientre, previene los dolores lumbares y el desgarro de la piel.\r\nTelas inteligentes, con componentes activos que al contacto con la piel liberan Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi, éstos ayudan a nutrir, hidratar y regenerar la piel.\r\n', 626.4, 'si', '', 'maternas', 'body', 'lizo', 'medianacompresion', '', '', '', '', '', '', '', ''),
(83, 'BRASIER POSTQUIRÚRGICO CON CONTROL DE BRAZOS', '11055', 'mujer', 'fajate', 'fajas', 'Brasier postquirúrgico elaborado con una tela elástica de compresión y copas prehormadas sin varillas. Ofrece cubrimiento de espalda y brazos, mientras realza naturalmente y centra el busto.', 'Brasier postquirúrgico elaborado con una tela elástica de compresión y copas prehormadas sin varillas. Ofrece control de espalda y brazos, realza naturalmente y centra el busto.\r\nTelas patentadas, impregnadas con componentes del grupo VivelTex, que al contacto con la piel liberan Gingko Biloba, Algas Marinas, Vitamina E y Cosmacol Emi, componentes que hidratan, nutren, regenera, cicatrizan y tonifican la piel.  ', 459.36, 'si', '', 'postquirurgica', 'brasier', 'broche', 'medianacompresion', '', '', '', '', '', '', '', ''),
(84, 'FAJA INVISIBLE TIPO CACHETERO', '11075', 'mujer', 'fajate', 'fajas', 'Faja de mediana compresión, para uso diario o postquirúrgico, tipo cachetero con realce de glúteos y abertura perineal.\r\n', 'Faja de mediana compresión, en el uso postquirúrgico, se utiliza en los primeros 10 días del post operatorio, ya que ejerce un moldeo suave, es también ideal para dormir en este proceso, ya que no tiene cierres ni broches que puedan causar alguna molestia y al ser de mediana compresión permite la correcta circulación y oxigenación de la sangre, permitiendo así un mejor descanso.\r\nPara el uso diario, es ideal para usar bajo vestidos o prendas ajustadas, ya que al no tener broches ni cierres, la hace invisible bajo la ropa. Está elaborada con una tela suave que simula la textura de la piel.\r\nEs tipo cachetero, tiene un encaje siliconado que no se marca bajo la ropa y no se arrolla.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel.', 535.92, 'si', 'none', 'postquirurgica', 'body', 'lizo', 'medianacompresion', '', '', '', '', '', '', '', ''),
(86, 'TIRANTES', '11083', 'mujer', 'fajate', 'accesorios', 'Cargaderas brasier.', 'Cargaderas brasier.', 83.52, 'si', 'none', '', '', '', '', '', '', '', '', '', '', '', ''),
(87, 'TABLA ADBOMINAL', '11101', 'mujer', 'fajate', 'accesorios', 'Tabla abdominal pequeña 10x23 cm.\r\n', 'Tabla abdominal de uso postquirúrgico, ayuda a evitar pliegues y a que la piel se adhiera más firme al musculo, alivia los dolores, estimula la eliminación de líquidos, acelerando la recuperación y los buenos resultados de cualquier procedimiento quirúrgico.\r\n', 125.28, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(88, 'Camiseta deportiva masculina con tecnologia', '508007R', 'hombre', 'leo', 'deportiva', '- Estampado localizado.\r\n- Silueta semiajustada.\r\n- Tela transpirable.\r\n- Secado rápido.\r\n- Ligera, liviana y ultracómoda.\r\n- Producida de manera sostenible en Colombia, bajo prácticas laborales justas.\r\n- Composición: 100% poliéster.', 'Esta camiseta deportiva cuenta con tecnología de secado rápido y material transpirable para que te sientas fresco y seco en muy poco tiempo. Es cómoda, fresca y liviana. Combínala con nuestras pantalonetas, licras o joggers deportivos y estarás listo para dar el máximo en tus rutinas.\r\n\r\n', 243.6, 'si', 'camisetas', '', '', '', '', '', '', '', '', '', '', '', ''),
(89, 'Top en algodón ultracómodo con cargaderas graduables', '91082', 'mujer', 'leonisa', 'ropainterior', 'Top en algodón sin estructuras, cómodo y ligero. Con espalda atlética para mayor soporte y libertad de movimiento.', 'Top en Algodón con Espalda Atlética y Máxima Comodidad\r\n• Elaborado en algodón suave que brinda frescura y confort\r\n• Diseño desestructurado, ligero e ideal para el uso diario\r\n• Perfecto para busto pequeño y mediano\r\n• Elástico suave en la base con apariencia plana que no marca la piel\r\n• Espalda atlética que mantiene las cargaderas en su lugar\r\n• Ajuste cómodo que se adapta naturalmente al cuerpo\r\n• Ideal para estar en casa, descansar o usar todo el día\r\n• Diseño práctico que combina funcionalidad y estilo casual\r\n• Sensación de suavidad, libertad y bienestar en cada uso', 132.24, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(91, 'FAJA POSTQUIRÚRGICA CONTROL TOTAL', '11103', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica de alta compresión con brasier incluido, brinda cubrimiento en espalda y control de brazos. Cuenta con doble refuerzo abdominal. Tiene 3 niveles de broches y abertura prineal.  \r\n', 'Faja postquirúrgica de alto control con cubrimiento en espalda que beneficia la región lumbar, alivia, evita las luxaciones y dolores de espalda, cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos. Cuenta con un brasier con mangas, que realza el busto y controla los brazos, tiene 3 medidas de broches y abertura perineal.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel, contribuyendo así a conseguir los resultados deseados luego de cualquier intervencion quirúrgica o estética.\r\n', 1287.6, 'si', '', 'postquirurgica', 'controltotal', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(92, 'FAJA POSTQUIRÚRGICA CONTROL TOTAL', '11103PLUS', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica de alta compresión con brasier incluido, brinda cubrimiento en espalda y control de brazos. Cuenta con doble refuerzo abdominal. Tiene 3 niveles de broches y abertura prineal.  \r\n', 'Faja postquirúrgica de alto control con cubrimiento en espalda que beneficia la región lumbar, alivia, evita las luxaciones y dolores de espalda, cuenta con doble refuerzo abdominal que brinda una compresión alta permitiendo el control firme, ayudando a controlar la inflamación, prevenir la retención de fluidos y agilizar el tiempo de curación y regeneración de tejidos. Cuenta con un brasier con mangas, que realza el busto y controla los brazos, tiene 3 medidas de broches y abertura perineal.\r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel, contribuyendo así a conseguir los resultados deseados luego de cualquier intervencion quirúrgica o estética.\r\n', 1329.36, 'si', '', 'postquirurgica', 'controltotal', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(93, 'TABLA ADBOMINAL ', '11109', 'mujer', 'fajate', 'accesorios', 'Tabla abdominal grande 20x30 cm. \r\n', 'Tabla abdominal de uso postquirúrgico, ayuda a evitar pliegues y a que la piel se adhiera más firme al musculo, alivia los dolores, estimula la eliminación de líquidos, acelerando la recuperación y los buenos resultados de cualquier procedimiento quirúrgico.\r\nElaborada con una espuma semi flexible forrada con telas frescas e hipoalergénicas, con componentes VivelTex.  \r\n', 160.08, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(94, 'TABLA ABDOMINAL AJUSTE BELCRO', '11121', 'mujer', 'fajate', 'accesorios', 'TABLA ,FAJON, POS QUIRÚRGICO', 'TABLA ,FAJON, POS QUIRÚRGICO, CON CUBRIMIENTO EN TODO EL ABDOMEN,AYUDANDO A QUE LA PIEL SE PEGUE  AL MUSCULO NUEVAMENTE,IDEAL PARA CIRUGÍAS  ABDOMINALES, VELCRO AJUSTABLE\r\n', 431.52, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(95, 'CHALECO COMPRESIVO CORRECTOR DE POSTURA', '11173', 'mujer', 'fajate', 'fajas', 'Faja de uso diario de alta compresión y total cubrimiento de espalda. 3 medidas de broches. Con varillas internas para mayor firmeza y corrección de postura. \r\n', 'Esta es una de nuestras fajas de uso diario, reductoras de fuerte compresión y espalda alta. sus broches tienen tres posiciones que se ajustan a tu medida. Es busto libre. Para uso diario que moldea y realza la figura brindando alto control en la zona deseada, disimula la flacidez y da firmeza a la piel, corrige la postura aliviando los dolores de espalda.\r\nCuenta con 3 varillas internas para brindar mayor firmeza, telas con componentes VivelTex, que nutren, regeneran e hidratan la pie.\r\n', 633.36, 'si', '', 'corredorpostura', 'cinturilla', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(96, 'FAJA A LA RODILLA CON CUBRIMIENTO DE ESPALDA', '11175', 'mujer', 'fajate', 'fajas', 'Esta es una faja que deja tu busto libre, su diseño con broches permite mayor ajuste, con cubrimiento medio en la espalda beneficiando la región lumbar, y conservar una mejor postura. Ejerce control de tus muslos.\r\n', 'Nivel de control\r\nAlto\r\nUsos recomendados\r\nUso-diarioPostquirúrgica\r\nZona de moldeo\r\nAbdominalPiernasGlúteos\r\nMecanismos de ajuste\r\nBroche\r\nMaterial\r\npowernetspandex\r\nEstilo\r\nA la rodilla\r\nBeneficios\r\n• Busto libre y espalda con sisa alta. • Abrochadura central de 3 niveles que permiten controlar la compresión. • Doble refuerzo abdominal para mayor compresión y firmeza. • Cubrimiento a la rodilla para definir piernas y glúteos\r\nCuidados de la prenda\r\n• El lavado: preferiblemente A MANO. Evite el uso de secadora. • Utilizar preferiblemente el Jabón Fajate• Evite usar ACCESORIOS que puedan dañar la prenda en el momento de ponerla (anillos, pulseras y uñas largas) • Lavar separadamente • Secar a la sombra• No utilizar blanqueadores.', 1113.6, 'si', '', 'postquirurgica', 'bustolibre', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(97, 'PROTECTORES DE HOMBROS', '11193', 'mujer', 'fajate', 'accesorios', 'Protector de hombros que se adaptan a las cargaderas, brindando mayor comodidad.', 'Protector de hombros que se adaptan a las cargaderas, brindando mayor comodidad.\r\n100% Poliester.', 83.52, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(98, 'FAJA PRIMERA POSTURA', '11198', 'mujer', 'fajate', 'fajas', 'Faja realce y control en abdomen,cubrimiento total en espalda,alivia dolor lumbar.Ideal para uso postquir', 'Faja realce y control en abdomen,cubrimiento total en espalda,alivia dolor lumbar.Ideal para uso postquir', 974.4, 'si', '', 'postquirurgica', 'bustolibre', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(99, 'FAJA PRIMERA POSTURA', '11198PLUS', 'mujer', 'fajate', '', 'Faja realce y control en abdomen,cubrimiento total en espalda,alivia dolor lumbar.Ideal para uso postquir', 'Faja realce y control en abdomen,cubrimiento total en espalda,alivia dolor lumbar.Ideal para uso postquir', 1044, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(100, 'PANTY   ULTRAREALCE  ', '11227', 'mujer', 'fajate', 'fajas', 'Panty ultrarealce Faja', 'Nivel control: Alto\r\nUso-diario, Ultra realce\r\nZona moldeo: Piernas,Con lebanta cola copmprecion en el axdomen \r\n', 598.56, 'si', '', 'levantagluteos', 'shorts', 'lizo', 'altacompresion', '', '', '', '', '', '', '', ''),
(101, 'FAJA ULTRA REALCE STRAPLESS', '11230', 'mujer', 'fajate', 'fajas', 'Faja cachetera strapless moldea y levanta los glúteos hasta 3 cm(*), controla fuerte y firmemente la zona abdominal moldeando tu cintura hasta 3cm(*) Importante. ¿Cómo sabes si eres talle corto? 1. Párate frente a un espejo con una posición recta. 2. Obtén la medida de tu talle tomando como punto de inicio la base del busto y como punto final la pelvis. 3. Si la medida que obtienes es igual o inferior a 28 cm esta referencia es para ti. Te recomendamos que al momento de seleccionar tu talla, elijas una adicional a lo que normalmente utilizas en prendas de control.', 'Nivel de control\r\nAlto\r\nUsos recomendados\r\nUso-diarioUltra realce\r\nZona de moldeo \r\nAbdominalGlúteos\r\nMecanismos de ajuste\r\nBroche\r\nMaterial\r\npowernetspandex\r\nEstilo\r\nCachetera\r\nBeneficios\r\n• Strapless para las blusas escotadas en hombros y espalda. • Cierre semi invisible en la zona perineal para mayor comodidad. • Estructura que moldea y da mayor volumen y forma a tus glúteos.\r\nCuidados de la prenda\r\n• El lavado: preferiblemente A MANO. Evite el uso de secadora. • Utilizar preferiblemente el Jabón Fajate• Evite usar ACCESORIOS que puedan dañar la prenda en el momento de ponerla (anillos, pulseras y uñas largas) • Lavar separadamente • Secar a la sombra• No utilizar blanqueadores', 890.88, 'si', '', 'postquirurgica', 'body', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(102, 'FAJA PRIMERA POSTURA SISA Y BUSTO LIBRE ', '11354', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica: primera postura, esencial durante las primeras semanas del postoperatorio.', 'Faja postquirúrgica: primera postura, esencial durante las primeras semanas del postoperatorio.', 960.48, 'si', '', 'postquirurgica', 'bustolibre', 'broche', 'medianacompresion', '', '', '', '', '', '', '', ''),
(103, 'PANTY FAJA CON REALCE DE GLUTEOS Y CONTROL EN ABDOMEN Y CINTURA ', '11226', 'mujer', 'fajate', 'fajas', 'Panty faja Ultrarealce que moldea y eleva los glúteos, ofreciendo control firme en abdomen, cintura, espalda, glúteos y caderas. Su diseño con refuerzo abdominal y propiedades que benefician la piel garantizan comodidad y una silueta definida. El elástico con silicona interna asegura un ajuste perfecto sin deslizamientos.\r\n\r\nDisimula la celulitis con costuras planas y encaje en las piernas para un ajuste preciso. Incluye cremallera perineal para mayor comodidad. Ideal para usar con vestidos, jeans o pantalones.', '- Forro interno en toda la prenda con componentes Viveltex\r\n- El color cocoa genera un efecto óptico para que no se marque con la ropa\r\n- Panty faja que brinda comodidad y versatilidad\r\n- Realce natural de glúteos\r\n- Encaje con silicona en muslos y elástico en bajo busto para mejor sujeción y que no se enrolle\r\n- Doble refuerzo abdominal para controlar y definir el abdomen\r\n- Costuras planas o invisibles que no maltratan la piel\r\n- Cremallera perineal para total comodidad\r\n- Control y moldeo total de torso\r\n- Perfecto moldeo de cintura y caderas con efecto de realce definido\r\n- Agradable aroma ', 730.8, 'si', '', 'levantagluteos', 'shorts', 'lizo', 'altacompresion', '', '', '', '', '', '', '', ''),
(104, 'Faja panty moldeadora con control abdominal firme y encaje ajustable', '11350', 'mujer', 'fajate', 'fajas', 'Transforma tu figura con la Faja Panty Moldeadora, que moldea cintura, abdomen y caderas. Con refuerzo abdominal para compresión firme y diseño de tiro alto que esculpe el torso.\r\n\r\nSu cremallera lateral, abrochadura interna y cierre perineal ofrecen comodidad y ajuste perfecto. Forrada en lycra con microcápsulas, cuida tu piel mientras te proporciona soporte. ¡Define tu estilo con confianza!', '- Faja panty de control alto que moldea muslos, abdomen, derrier y glúteos.\r\n- Moldea la silueta desde la base del busto hasta la mitad de las piernas.\r\n- Doble refuerzo abdominal que controla y da firmeza.\r\n- Disimula la celulitis.\r\n- Encaje elástico con silicona en la base del busto que facilita que la prenda permanezca en su lugar.\r\n- Imperceptible bajo la ropa con costuras planas que no maltratan la piel.\r\n- Cremallera perineal que facilita las idas al baño.\r\n- Cremallera lateral con abrochadura interna que facilita la postura y protege la piel.\r\n- Uso para jeans, vestidos o pantalones.', 946.56, 'si', '', 'levantagluteos', 'shorts', 'cierre', 'altacompresion', '', '', '', '', '', '', '', ''),
(105, 'Faja postquirúrgica a la rodilla y mangas con control medio fit 360', '11353', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica ideal para las primeras semanas de recuperación. Ofrece control moderado, ayuda en la eliminación de fluidos y desinflamación, y es perfecta para cirugías de espalda y brazos. Su diseño fit 360 moldea glúteos y se adapta a caderas amplias.\r\n', 'Con cierre perineal y cargaderas ajustables para comodidad durante el uso. Tela que proporciona un ajuste seguro y confortable, recomendado para uso las 24 horas según indicación médica.- Ideal para las primeras semanas de recuperación\r\n- Mediana compresión para desinflamar y mayor comodidad\r\n- Cierre perineal ideal para postoperatorios y uso diario\r\n- Uso diario nocturno durante recuperación\r\n- Mangas para mayor cubrimiento después de intervención de brazos y espalda\r\n- Cola fit 360 para mayor capacidad en la zona de los glúteos\r\n- Tela con apariencia brillante que proporciona un ajuste cómodo', 1141.44, 'si', '', 'postquirurgica', 'controltotal', 'broche', 'medianacompresion', '', '', '', '', '', '', '', ''),
(106, 'FAJA POSTQUIRURGICA  A LA RODILLA CON SOPORTE ABDOMINAL Y CUBRIMIENTO DE ESPALDA ', '11355', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica con soporte abdominal, ajuste personalizado y tres niveles de broches. Moldea cintura, caderas y piernas, ideal para postparto, postoperatorio o uso diario. Con refuerzo abdominal y detalles de encaje para un ajuste perfecto.\r\n\r\nFabricada con lycra forrada y microcápsulas Viveltex, levanta glúteos y estiliza 360°. Costuras planas para mayor confort y protección de la piel.', ' BENEFICIOS\r\n- Forro interno en toda la prenda con componentes Viveltex\r\n- Tela externa en powernet es la encargada de brindar una alta comprensión\r\n- El color cocoa genera un efecto óptico para que no se marque con la ropa\r\n- Tres niveles de broches que permite graduarla\r\n- Mayor capacidad en la zona de los glúteos que los realza y define la cintura\r\n- Doble refuerzo abdominal para controlar y definir el abdomen\r\n- Costuras planas o invisibles que no maltratan la piel\r\n- Falso perineal para total comodidad\r\n- Evita la retención de líquidos y la formación de fibrosis\r\n- Es una faja compresiva, disminuye el dolor y brinda seguridad en tus movimientos\r\n- El cubrimiento total en tu espalda te da una postura estilizada\r\n- Tiene un perfecto moldeo de cintura y caderas con efecto de realce definido\r\n- Agradable aroma', 1211.04, 'si', '', 'postquirurgica', 'bustolibre', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(107, 'Faja postquirúrgica de alta compresión con busto libre mangas y control abdominal', '11360', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica de alta compresión ideal para cicatrización y recuperación. Fabricada con powernet externo y lycra interna, ofrece beneficios para la piel, control de espalda y ajuste personalizado con abrochadura de 3 niveles y 19 ganchos para mejorar la postura. Perfecta para uso diario y postcirugía, casi invisible bajo la ropa.\r\n', 'Incluye refuerzo abdominal para un control firme, cierre perineal para comodidad y diseño de cola fit 360 para moldear glúteos. Con delicado encaje en el ruedo, es una excelente opción para cirugías de espalda y brazos.- Forro interno en toda la prenda con componentes Viveltex.\r\n- El color cocoa genera un efecto óptico para que no se marque con la ropa.\r\n- Cremallera lateral con broches internos brinda un ajuste perfecto y ayuda a la desinflamación uniforme.\r\n- Estiliza los glúteos y resalta las curvas y la cintura con su cola fit 360.\r\n- Doble refuerzo abdominal para controlar y definir tu abdomen.\r\n- Costuras planas o invisibles que no maltratan la piel.\r\n- Elástico superior que ayuda a la correcta sujeción en torso.\r\n- Brasier separado del torso por medio de broches, que permite la asepsia luego de una cirugía estética y facilita la \r\n  lactancia.\r\n- Cierre perineal para total comodidad.', 1322.4, 'si', '', 'postquirurgica', 'bustolibre', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(108, 'Faja postquirúrgica con brasier hasta la rodilla de alta compresión', '11366', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica de alta compresión ideal para cicatrización y recuperación. Fabricada con powernet externo y lycra interna, ofrece beneficios para la piel, control de espalda y ajuste personalizado con abrochadura de 3 niveles y 19 ganchos para mejorar la postura. Perfecta para uso diario y postcirugía, casi invisible bajo la ropa.\r\n\r\nIncluye refuerzo abdominal para un control firme, cierre perineal para comodidad y diseño de cola fit 360 para moldear glúteos. Con delicado encaje en el ruedo, es una excelente opción para cirugías de espalda y brazos.', '- Forro interno en toda la prenda con componentes Viveltex.\r\n- El color cocoa genera un efecto óptico para que no se marque con la ropa.\r\n- Cremallera lateral con broches internos brinda un ajuste perfecto y ayuda a la desinflamación uniforme.\r\n- Estiliza los glúteos y resalta las curvas y la cintura con su cola fit 360.\r\n- Doble refuerzo abdominal para controlar y definir tu abdomen.\r\n- Costuras planas o invisibles que no maltratan la piel.\r\n- Elástico superior que ayuda a la correcta sujeción en torso.\r\n- Brasier separado del torso por medio de broches, que permite la asepsia luego de una cirugía estética y facilita la \r\n  lactancia.\r\n- Cierre perineal para total comodidad.\r\n- Control y moldeo total de torso.', 1440.72, 'si', '', 'postquirurgica', 'controltotal', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(109, 'Faja postquirúrgica moldeadora a media pierna con busto libre y soporte', '11378', 'mujer', 'fajate', 'fajas', 'Faja postquirúrgica moldeadora de alta compresión, controla abdomen, muslos, torso y caderas. Con cremallera lateral y broches internos para ajuste preciso, alivia dolores lumbares y promueve desinflamación. El doble refuerzo abdominal previene la retención de líquidos y acelera la cicatrización.', 'Diseñada con encaje delicado, powernet exterior para moldeado y lycra interna que cuida la piel. Cola fit 360 realza los glúteos, y el cierre perineal mejora la comodidad. Ideal para recuperación postquirúrgica y uso diario.- Alta comprensión en zona abdominal\r\n- Moldeo de cadera, muslos y torso\r\n- Favorece la recuperación después de procesos postquirúrgicos\r\n- Evita la flacidez\r\n- Cierre lateral con recubrimiento interior permite una postura más cómoda previniendo irritaciones\r\n- Componentes que benefician la piel y la cicatrización\r\n- Mayor capacidad en la zona de los glúteos que los realza, moldea y estiliza gracias a su cola fit 360\r\n- Costuras planas y lisas que la hacen más sutil con tu ropa exterior\r\n- Favorece la buena postura\r\n- Cargaderas removibles', 1238.88, 'si', '', 'postquirurgica', 'bustolibre', 'cierre', 'altacompresion', '', '', '', '', '', '', '', ''),
(110, 'Faja postquirúrgica Fit 360 cachetera de alta compresión y realce de glúteos', '11380', 'mujer', 'fajate', 'fajas', 'La faja postquirúrgica de alta compresión controla abdomen, caderas, espalda y glúteos, favoreciendo la recuperación postoperatoria. Con cargaderas graduables y tres niveles de ajuste, ofrece un ajuste personalizado y alivia dolores lumbares. Su encaje siliconado garantiza sujeción firme y cómoda.\r\n\r\nEl color cocoa asegura discreción bajo la ropa, mientras que el diseño Cola Fit 360 realza los glúteos. Además, el cierre perineal facilita el uso diario, brindando confort y practicidad durante todo el día.', '- Compresión alta - previene la retención de líquidos.\r\n- Compresión y cubrimiento en caderas, abdomen, espalda y glúteos, forrada con tela suave y componentes Viveltex.\r\n- Diseñada con costuras planas y lisas que la hacen más sutil con tu ropa exterior.\r\n- Usándola a diario favorece la buena postura y moldea el cuerpo de forma uniforme y natural.\r\n- Acelera y ayuda en la recuperación postquirúrgica.\r\n- Cargaderas removibles con almohadilla.\r\n- Cierre perineal que facilita las idas al baño.', 1092.72, 'si', '', 'postquirurgica', 'bustolibre', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(111, 'Faja de alta compresión con varillas para moldear cintura y abdomen', '11478', 'mujer', 'fajate', 'fajas', 'Faja ultrafit skin con varillas, ideal para moldear y resaltar las curvas. Ofrece alta compresión para definir la cintura y proporciona un contorno curvilíneo al instante, especialmente en el abdomen bajo. Ayuda a corregir la postura, reducir la apariencia de los rollitos y mejora la figura.', 'Con 4 niveles de abrochadura y 17 ganchos en la parte frontal, más 4 niveles en los hombros, garantiza un ajuste perfecto. Las 4 varillas mantienen el molde y previenen que la faja pierda forma. Su falso perineal y tabla lumbar ofrecen comodidad y alivian molestias postquirúrgicas. Asegúrate de medir cintura y caderas para un ajuste adecuado.- Faja postquirúrgica silueta de cuerpo de guitarra que moldea y resalta las curvas, reduciendo visualmente la \r\n cintura y destacando los glúteos.\r\n- Control abdominal adicional.\r\n- Funciona como corrector de postura, mejorando la apariencia.\r\n- Previene los dolores asociados a la mala postura.\r\n- Cuenta con una tabla lumbar en la parte posterior que evita la retención de líquidos favoreciendo el drenaje de \r\n  estos.\r\n- Abrochadura de 4 niveles y 17 ganchos en su parte frontal y en los hombros una abrochadura de 4 niveles por 2 \r\n  ganchos en cada uno para mayor ajuste.\r\n- Falso perineal para brindar comodidad en las idas al baño.', 1197.12, 'si', '', 'postquirurgica', 'bustolibre', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(112, 'Faja corrector de postura de alta compresión con refuerzo abdominal', '11481', 'mujer', 'fajate', 'fajas', 'Faja correctora de postura de alta compresión que moldea abdomen, cintura, espalda y caderas. Con refuerzos en X para mejorar la postura, material powernet que estiliza el cuerpo y libera nutrientes beneficiosos para la piel.\r\n', 'Sistema de ajuste con broches en el frente y hombros, cargaderas graduables y cierre perineal para mayor comodidad. Silicona en el encaje asegura sujeción sin irritaciones. Ideal para uso diario y recuperación.- Faja correctora de postura de alta compresión\r\n- Controla el abdomen alto, medio y bajo\r\n- Moldea la cintura, espalda, cadera y abdomen\r\n- Facilita una mejor postura gracias a los cortes de refuerzo en X en la espalda y el abdomen, elaborados con \r\n  material de compresión\r\n- Sistema de ajuste delantero con abrochadura de 3 niveles y 19 ganchos, y en hombros una abrochadura de 4 niveles y \r\n  dos ganchos para mayor ajuste y facilidad de postura\r\n- Cargadera graduable de 30 centímetros en la parte superior del busto que centra el busto y mantiene la faja en su  \r\n  lugar\r\n- Delicado detalle de encaje con silicona de micropuntos que se adhiere a la piel para su correcta sujeción sin \r\n  causar irritabilidad', 939.6, 'si', '', 'postquirurgica', 'bustolibre', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(113, 'Panty faja moldeadora de alta compresión y realce de glúteos a media pierna', '11482', 'mujer', 'fajate', 'fajas', 'Faja panty moldeadora de control medio que define cintura, espalda y caderas. Con abrochadura ajustable y doble refuerzo abdominal para mayor firmeza. Su cierre perineal facilita las idas al baño.', 'Resalta los glúteos con un efecto redondeado y firme, mientras el elástico con silicona asegura un ajuste perfecto. Forrada en lycra con microcápsulas que cuidan tu piel mientras moldean tu figura.- Faja panty de control alto que moldea muslos, abdomen, derrier y glúteos\r\n- Moldea la silueta desde el abdomen medio hasta la mitad de las piernas\r\n- Doble refuerzo abdominal que controla y da firmeza\r\n- Disimula la celulitis\r\n- Elástico con 3 líneas de silicona facilitando que la prenda permanezca en su lugar\r\n- Imperceptible bajo la ropa con costuras planas que no maltratan la piel\r\n- Cremallera perineal que facilita las idas al baño, con gancho que impide que se abra\r\n- Abrochadura con 4 niveles de ajuste y 12 ganchos que facilita la postura\r\n- Uso para jeans, vestidos o pantalones', 696, 'si', '', 'levantagluteos', 'shorts', 'broche', 'altacompresion', '', '', '', '', '', '', '', ''),
(114, 'Panty moldeador con control de abdomen y realce para glúteos', '15116', 'mujer', 'fajate', 'ropainterior', 'Panty básico diseñado para ofrecer un excelente control del abdomen y realzar la forma de tus glúteos. Confeccionado en una tela gruesa que ayuda a ocultar la celulitis, este panty crea una silueta hermosa y estilizada.\r\n', 'El elástico grueso en la parte inferior no solo mejora el ajuste, sino que también proporciona una sujeción adicional, asegurando que la prenda se mantenga en su lugar durante todo el día. Ideal para usar bajo cualquier atuendo, este panty es la elección perfecta para quienes buscan comodidad y estilo en su ropa interior.- Panty control de abdomen.\r\n- Levanta cola. Estiliza la figura.\r\n- Resorte que evita que se enrolle.\r\n- Cubrimiento de imperfecciones.', 619.44, 'si', 'panties', '', '', '', '', '', '', '', '', '', '', '', ''),
(115, 'TABLA ABDOMINAL POSTQUIRURGICA TIPO PERA PARA DRENAJE Y PREVENSION DE FIBROSIS', '11146', 'mujer', 'fajate', 'accesorios', 'Tabla abdominal postoperatoria ideal para acelerar el proceso de recuperacion. Se puede usar debajo de cualquier faja ajustada o faja moldeadora para aplanar el abdomen.', 'Una tabla de compresión es una gran adición a cualquier faja. Esta tabla le ayudará a mantener su faja en la posición correcta y recta. BENEFICIOS:\r\n-Ayuda en el drenaje\r\n-Aumenta los efectos de las Fajas.\r\n-Proporciona una compresión uniforme en la zona abdominal.', 139.2, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(116, 'ALMOHADILLA LUMBAR  POSTQUIRURGICA PARA RECUPERACION Y MOLDEADO DE FIGURA ', '11389', 'mujer', 'fajate', 'accesorios', 'Almohadilla lumbar en espuma para uso postquirúrgico, Es una complemento ideal para la recuperación luego de un procedimiento estético, evita la retención de líquidos en la zona de la cintura o flancos, y ayuda a moldear la figura definiendo más el derrier.', 'BENEFICIOS:\r\n- Favorece la recuperación postquirúrgica : Brinda soporte y estabilidad en la zona lumbar después de procedimientos estéticos como liposucción o lipoescultura.\r\n- Evita la retención de líquidos : Reduce la acumulación de líquidos en la zona de la cintura y los flancos, favoreciendo un proceso de desinflamación más rápido.\r\n- Moldea la figura : Ayuda a definir mejor la silueta, especialmente en la zona de la espalda baja y cintura.\r\n- Realza el derrier : Su uso contribuye a una mejor distribución de la presión, resaltando y definiendo la forma de los glúteos.\r\n- Brinda comodidad y soporte : Su espuma de alta densidad proporciona una sensación cómoda mientras protege la zona intervenida.\r\n- Facilita una recuperación más segura : Disminuye la presión en los tejidos afectados, ayudando a evitar irregularidades o fibrosis.\r\n- Compatible con fajas postquirúrgicas : Se adapta perfectamente para complementar el uso de fajas y mejorar los resultados.', 118.32, 'si', 'none', '', '', '', '', '', '', '', '', '', '', '', ''),
(117, 'Tabla postquirúrgica tipo mariposa', '11516', 'mujer', 'fajate', 'accesorios', 'La Tabla Mariposa Postquirúrgica Lumbar es el aliado perfecto para una recuperación cómoda y efectiva después de una cirugía lumbar. Diseñada para ayudar a mantener una postura erguida, esta almohadilla lumbar está especialmente diseñada para disminuir los dolores de espalda y promover una recuperación óptima.', '• Evita el desarrollo de fibrosis \r\n• Facilita una mejor postura erguida y correcta \r\n• Reduce el dolor gracias a la presión \r\n• Sus 4 líneas laterales permiten la correcta ubicación en el abdomen, la parte lisa va en contacto con la piel \r\n• Mantiene el abdomen plano \r\n• Ayuda en el drenaje de líquidos inflamatorios', 215.76, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(118, 'Tabla postoperatoria abdominal para drenaje y prevención de fibrosis', '11517', 'mujer', 'fajate', 'accesorios', 'Tabla abdominal con diseño de 4 rayas laterales, fabricada en poliuretano flexible y poliéster, ideal para postoperatorios. Facilita el drenaje de líquidos inflamatorios y previene la formación de fibrosis, ayudando en la recuperación.\r\n\r\nPromueve una postura erguida y correcta para mantener el abdomen plano. Su diseño reduce el dolor y la incomodidad, proporcionando una compresión uniforme y efectiva.', '- Evita el desarrollo de fibrosis\r\n- Facilita una mejor postura erguida y correcta\r\n- Reduce el dolor gracias a la presión\r\n- Sus 4 líneas laterales permiten la correcta ubicación en el abdomen, la parte lisa va en contacto con la piel\r\n- Mantiene el abdomen plano\r\n- Ayuda en el drenaje de líquidos inflamatorios', 292.32, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(119, 'Faja tipo panty media pierna de alta compresión y realce de glúteo', '11346', 'mujer', 'fajate', '', 'La faja panty moldea cintura, espalda y caderas en 360°, ofreciendo una silueta definida. Su diseño de tiro alto y ajuste con abrochadura mejora la postura, mientras que el cierre perineal brinda comodidad.\r\n\r\nRealza los glúteos de forma natural y asegura un ajuste perfecto con encaje elástico y silicona. Forrada con lycra y microcápsulas, cuida la piel mientras define caderas y glúteos.', '- Faja panty de control alto que moldea muslos, abdomen, derrier y glúteos.\r\n- Moldea la silueta desde la base del busto hasta la mitad de las piernas.\r\n- Doble refuerzo abdominal que controla y da firmeza.\r\n- Disimula la celulitis.\r\n- Encaje elástico con silicona en la base del busto que facilita que la prenda permanezca en su lugar, con varillas \r\n  que impiden que se recoja o de doble.\r\n- Imperceptible bajo la ropa con costuras planas que no maltratan la piel.\r\n- Cremallera perineal que facilita las idas al baño.\r\n- Abrochadura con 2 niveles de ajuste y 17 ganchos que facilita la postura.\r\n- Uso para jeans, vestidos o pantalones.', 835.2, 'si', '', '', '', '', '', '', '', '', '', '', '', '', ''),
(120, 'BOXER DE HOMBRE CONTROL ABDOMEN', '11079', 'hombre', 'fajate', 'fajas', 'Es un bóxer elaborado con materiales suaves y elásticos con control de abdomen, que brindan un soporte firme y seguro.\r\n', 'Boxer de hombre, con control de abdomen y espalda.\r\nAbajo es como un bóxer normal, la compresión se ejerce de la cadera hacia arriba.\r\nElaborado con telas inteligentes, telas frescas e hipoalergénicas, que no calientan ni causan molestias en la piel. \r\nAl no tener broches ni cierres y estar elaborado con telas suaves, se vuelve imperceptible bajo la ropa exterior. \r\nTelas con componentes VivelTex que al contacto con la piel liberan: Gingko Biloba, Algas Marinas, Vitamina E, Cosmacol Emi. Éstos componentes nutren, regeneran, cicatrizan, hidratan y tonifican la piel.', 556.8, 'si', 'none', 'levantagluteos', 'shorts', 'lizo', 'altacompresion', '', '', '', '', '', '', '', ''),
(121, 'BRASIER MAGIC UP DE REALCE ALTO', '1223000', 'mujer', 'leonisa', 'ropainterior', 'El brasier de realce Magic Up centra y levanta el busto, para que tengas ese escote que te hará lucir radiante. Los encajes en SmartLace® te cubren de sensualidad y te dan excelente modelación. Un brasier para deslumbrar y resaltar tu feminidad.', 'Brasier triangular de cubrimiento medio que realza el escote.\r\nIdeal para busto pequeño y regular.\r\nÚsalo con escotes profundos y en los momentos más sensuales.\r\nAlmohadillas removibles para graduar el nivel de realce: medio o alto.\r\nElaborado con encaje SmartLace® que se ajusta perfectamente a tu cuerpo.\r\nCargaderas multiusos para usar en modo convencional, cruzadas o halter.\r\nComposición: poliamida 86.6%, elastano 13.3%, poliéster 0.1%.', 348, 'si', 'brasieres', '', '', '', '', 'pushup', '', '', '', '', '', '', ''),
(122, 'BRASIER DE LACTANCIA SIN ARCO CON SEÑALIZADOR', '11338', 'mujer', 'leonisa', 'ropainterior', 'Brasier de lactancia sin arco. Máxima comodidad, suavidad y practicidad para alimentar a tu bebé', 'Brasier de Lactancia sin Arco con Copas de Alto Cubrimiento\r\n• Composición: 41% poliamida – 29% poliéster – 16% algodón – 14% elastano\r\n• Diseño especial para lactancia que brinda comodidad y facilidad de uso\r\n• Copas completas con forro interno que cubren totalmente el busto\r\n• Sin arco y sin costuras en copas: no se marca en la ropa\r\n• Broche en la unión de las copas que permite alimentar al bebé sin quitar el brasier\r\n• Sistema práctico que facilita el acceso rápido y cómodo durante la lactancia\r\n• Señalizador integrado para recordar el último seno utilizado\r\n• Tela suave y fresca que cuida la piel durante todo el día\r\n• Ajuste perfecto que se adapta a los cambios del cuerpo\r\n• Diseño pensado para brindar soporte sin sacrificar comodidad\r\n• Ideal para uso diario durante la etapa de lactancia\r\n• Combina funcionalidad, suavidad y practicidad en una sola prenda\r\n• Sensación de confort, seguridad y bienestar en cada uso', 348, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(123, 'Paquete X2 Brasier sin arco multibra con broche delantero', '11473X2', 'mujer', 'leonisa', 'ropainterior', 'Brasier postural y deportivo con refuerzo en X. Soporte total, control y comodidad sin arco.', 'Brasier de Soporte con Refuerzo en X en PowerSlim® y Control Total\r\n• Composición: 90% poliamida – 10% elastano\r\n• Forro: 91% poliamida – 9% elastano\r\n• Refuerzo en X en la espalda elaborado en PowerSlim® que mejora la postura\r\n• Diseño sin arco que brinda libertad de movimiento y máxima comodidad\r\n• Copas en doble capa de DuraFit® que ofrecen cubrimiento total y modelación natural\r\n• Controla el volumen del busto y proporciona una forma redondeada\r\n• Banda ancha bajo el busto que aporta soporte firme durante todo el día\r\n• Ideal para uso postquirúrgico, deportivo o diario\r\n• PowerSlim® en espalda y laterales que estiliza la silueta y disimula rollitos\r\n• Costuras ultrasuaves que evitan molestias y roces en la piel\r\n• Cargaderas acolchadas que brindan mayor confort en hombros\r\n• Abrochadura frontal con 6 broches y 2 niveles de ajuste para fácil uso\r\n• Ajuste seguro que se adapta perfectamente al cuerpo\r\n• Permite moverte con libertad sin sacrificar soporte\r\n• Sensación de firmeza, control y bienestar en cada uso', 696, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(124, 'BRASIER CORRECTOR DE POSTURA CON SOPORTE DE ESPALDA EN X', '11473', 'mujer', 'leonisa', 'ropainterior', 'Brasier corrector de postura con refuerzo en X. Máximo soporte, compresión y comodidad para uso diario.', 'Brasier Corrector de Postura con Refuerzo en X y Control Fuerte\r\n• Composición: 90% poliamida – 10% elastano\r\n• Diseño con refuerzo en X en la espalda que ayuda a mantener una postura erguida\r\n• Sin arco para mayor comodidad y libertad de movimiento\r\n• Abrochadura delantera que facilita su uso y ajuste\r\n• Copas de alto cubrimiento en doble capa de DuraFit®: suaves, livianas y resistentes\r\n• Nivel de compresión fuerte que mantiene el busto firme y controlado\r\n• Espalda y sisa en PowerSlim® que estilizan la silueta y ayudan a disimular rollitos\r\n• Ideal para busto grande que requiere soporte extra\r\n• Cargaderas anchas, ergonómicas y graduables que distribuyen el peso sin incomodar\r\n• Reduce la presión en hombros y espalda, mejorando la postura corporal\r\n• Uso versátil: perfecto para el día a día, ejercicio, postoperatorio, lactancia o descanso\r\n• Ajuste cómodo que se adapta al cuerpo brindando soporte continuo\r\n• Diseño funcional que combina control, bienestar y practicidad\r\n• Sensación de firmeza, alivio y seguridad durante todo el día', 424.56, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
(125, 'BRASIER DE COPA COMPLETA CON ARCO Y ENCAJE', '11492', 'mujer', 'leonisa', 'ropainterior', 'Brasier de copas grandes con arco y sin realce. Máximo cubrimiento, soporte y elegancia en encaje.', 'Brasier Triangular con Arco en SmartLace® para Busto Grande\r\n• Composición: 85% poliamida – 15% elastano\r\n• Forro: 92% poliamida – 8% elastano\r\n• Silueta triangular con arco interno que brinda soporte firme y seguro\r\n• Copas de gran cubrimiento sin espuma ni realce para una modelación natural\r\n• Forro interno en las copas que evita transparencias y aporta mayor comodidad\r\n• Elaborado en encaje elástico SmartLace® que aporta un look femenino y delicado\r\n• Varillas laterales que ayudan a centrar el busto y mejorar la forma\r\n• Cargaderas anchas que brindan mayor soporte y confort durante todo el día\r\n• Ajuste perfecto que se adapta a tu medida con total comodidad\r\n• Abrochadura posterior de 2 ganchos con 3 niveles de ajuste\r\n• Ideal para uso diario en busto grande\r\n• Diseño que combina soporte, elegancia y funcionalidad\r\n• Sensación de firmeza, suavidad y confianza en cada uso', 348, 'si', 'brasieres', '', '', '', '', '', '', '', '', '', '', '', ''),
